mapper.select:
SELECT -- product p.id AS product_id, p.name AS product_name, p.product_type AS product_type, p.start_date AS start_date, p.end_date AS end_date, -- company ic.id AS company_id, ic.name AS company_name, ic.tel AS company_phone, ic.homepage AS company_website, ic.image_url AS company_image_url, -- rating CASE WHEN IFNULL(r.analysis_count, 0) >= 10 THEN 5 WHEN IFNULL(r.analysis_count, 0) = 0 THEN 0 ELSE ROUND(r.analysis_count / 2) END AS rating, -- coverage cm.id AS coverage_id, cm.name AS coverage_name, cm.description AS coverage_description, cv.coverage_amount AS coverage_amount, cv.waiting_period_days AS coverage_waiting_days, cv.benefit_limit AS coverage_benefit_limit, -- premium pc.id AS premium_id, pc.min_age AS premium_min_age, pc.max_age AS premium_max_age, pc.gender AS premium_gender, pc.premium AS premium_amount, pc.payment_period_years AS premium_payment_years, pc.insurance_period_years AS premium_insurance_years, CASE WHEN #{custId} IS NOT NULL AND ca.id IS NOT NULL THEN 1 ELSE 0 END AS liked, y.liked_count FROM insurance_product p JOIN insurance_company ic ON ic.id = p.company_id LEFT JOIN product_coverage cv ON cv.product_id = p.id LEFT JOIN coverage_master cm ON cm.id = cv.coverage_id LEFT JOIN premium_condition pc ON pc.product_id = p.id LEFT JOIN ( SELECT product_id, COUNT(*) AS analysis_count FROM coverage_analysis GROUP BY product_id ) r ON r.product_id = p.id LEFT JOIN customer_act ca ON ca.product_id = p.id
and ca.customer_id = #{custId}
LEFT JOIN ( SELECT product_id, COUNT(*) AS liked_count FROM customer_act where good = 'Y' group by product_id ) y ON y.product_id = p.id WHERE p.id = #{productId} ORDER BY cm.id, pc.min_age
